const a = [
  {"id":3490,"text":"Which of the following correctly describes Kussmaul's sign?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 544.","responses":[{"text":"Paradoxical rise in the jugular venous pressure during inspiration","correct":true,"visible":false},{"text":"Paradoxical drop in the jugular venous pressure during expiration","correct":false,"visible":false},{"text":"Paradoxical rise in the jugular venous pressure during expiration","correct":false,"visible":false},{"text":"Paradoxical drop in the jugular venous pressure during inspiration","correct":false,"visible":false},{"text":"Paradoxical rise of the pulse rate during inspiration","correct":false,"visible":false}]},{"id":3494,"text":"What is the most specific marker for myocardial infarction?","explanation":"**Troponin-I** is a **highly specific and sensitive marker** for myocardial infarction. It rises within 3-12 hours following the onset of symptoms and can remain elevated for up to 10-14 days, making it useful for both early diagnosis and late presentation.\r\n\r\n\r\nCreatine phosphokinase-MB (CK-MB) is an older marker and is not as specific as troponin-I. It can be elevated in conditions like skeletal muscle injury.\r\n\r\nCreatine phosphokinase-BB (CK-BB) is predominantly found in the brain and is not specific for cardiac tissue.\r\n\r\nAlkaline phosphatase is not a marker for myocardial infarction; it is more relevant for liver and bone pathology.\r\n\r\nLactate dehydrogenase (LDH or LD) is also less specific for myocardial infarction and can be elevated in many other conditions such as hemolysis, liver disease, and some cancers.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 74.","responses":[{"text":"Lactate dehydrogenase (LDH or LD)","correct":false,"visible":false},{"text":"Creatine phosphokinase-MB (CK-MB)","correct":false,"visible":false},{"text":"Creatine phosphokinase-BB (CK-BB)","correct":false,"visible":false},{"text":"Alkaline phosphatase","correct":false,"visible":false},{"text":"Troponin-I","correct":true,"visible":false}]},{"id":3511,"text":"Diastolic heart failure in a 65-year-old man is predominantly due to which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 529.","responses":[{"text":"Bilateral renal artery stenosis","correct":false,"visible":false},{"text":"Cardiomyopathy","correct":false,"visible":false},{"text":"Hypertension","correct":true,"visible":false},{"text":"Diabetes mellitus","correct":false,"visible":false},{"text":"Obesity","correct":false,"visible":false}]},{"id":3514,"text":"A 4-year-old boy is brought by his parents with the complaint that he frequently catches a cold and gets cough. According to the parents, he had pneumonia thrice this year and had to be admitted to the hospital one time. On examination, an ejection systolic murmur is heard on the left upper sternal border with a fixed splitting of the second heart sound. The first heart sound is loud. What is the most likely diagnosis?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 298-299.","responses":[{"text":"Patent ductus arteriosus","correct":false,"visible":false},{"text":"Atrial septal defect","correct":true,"visible":false},{"text":"Ventricular septal defect","correct":false,"visible":false},{"text":"Coarctation of aorta","correct":false,"visible":false},{"text":"Cystic fibrosis","correct":false,"visible":false}]},{"id":3525,"text":"What is the pathogenesis of hyaline arteriosclerosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 490.","responses":[{"text":"Intake of extracellular calcium leading to hyperreactivity","correct":false,"visible":false},{"text":"Intimal degradation","correct":false,"visible":false},{"text":"Deposition of extracellular matrix","correct":true,"visible":false},{"text":"Medial hypertrophy","correct":false,"visible":false},{"text":"Atherosclerotic plaque disruptions","correct":false,"visible":false}]},{"id":3526,"text":"A murmur heard from right second intercostal space extending to the left sternal border is associated with what?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 300.","responses":[{"text":"Aortic stenosis","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Mitral regurgitation","correct":false,"visible":false},{"text":"Tricuspid regurgitation","correct":false,"visible":false},{"text":"Aortic regurgitation","correct":true,"visible":false}]},{"id":3528,"text":"Which of the following are minor manifestations of rheumatic fever according to Jones criteria?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 559.","responses":[{"text":"Purpuric rash and cough","correct":false,"visible":false},{"text":"Fever and tachycardia","correct":false,"visible":false},{"text":"Jaundice and edema","correct":false,"visible":false},{"text":"Migratory polyarthritis, carditis, subcutaneous nodules, erythema marginatum, Sydenham chorea","correct":false,"visible":false},{"text":"Fever and elevated erythrocyte sedimentation rate (ESR)","correct":true,"visible":false}]},{"id":3530,"text":"What does lidocaine do?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 252.","responses":[{"text":"Increase the amplitude of QRS complex","correct":false,"visible":false},{"text":"Increase action potential duration","correct":false,"visible":false},{"text":"Decrease conductivity","correct":false,"visible":false},{"text":"Increase PR interval","correct":false,"visible":false},{"text":"Reduce action potential duration","correct":true,"visible":false}]},{"id":3536,"text":"A patient presents with an apex beat heaving with a thrill in the left 5th intercostal space. Which association is most likely?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 521.","responses":[{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Mitral regurgitation","correct":true,"visible":false},{"text":"Pulmonic stenosis","correct":false,"visible":false},{"text":"Tricuspid stenosis","correct":false,"visible":false},{"text":"Tricuspid regurgitation","correct":false,"visible":false}]},{"id":3537,"text":"A continuous, \"machine-like\" murmur is associated with what congenital pathology?","explanation":"A **patent ductus arteriosus** presents with a characteristic **\"machine-like\" murmur**, usually **continuous** in nature. The murmur results from a continuous shunt of blood between the aorta and the pulmonary artery, bypassing the lungs.\r\n\r\n\r\nTetralogy of Fallot usually presents with a harsh systolic murmur due to pulmonic stenosis.\r\n\r\nCoarctation of the aorta generally causes a systolic murmur best heard on the back, but it is not continuous or \"machine-like.\"\r\n\r\nAtrial septal defect (ASD) produces a systolic ejection murmur but does not have the \"machine-like\" quality.\r\n\r\nVentricular septal defect (VSD) generally causes a holosystolic murmur, not a continuous one.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 535.","responses":[{"text":"Coarctation of aorta","correct":false,"visible":false},{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Teratology of Fallot","correct":false,"visible":false},{"text":"Ventricular septal defect","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":true,"visible":false}]},{"id":3538,"text":"What congenital defect is rubella most commonly associated with?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 77.","responses":[{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Teratology of Fallot","correct":false,"visible":false},{"text":"Bicuspid aortic valve","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":true,"visible":false},{"text":"Coarctation of aorta","correct":false,"visible":false}]},{"id":3539,"text":"An atrial septal defect is most strongly associated with what chromosomal syndrome?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 77.","responses":[{"text":"Down syndrome","correct":true,"visible":false},{"text":"Turner syndrome","correct":false,"visible":false},{"text":"Edwards syndrome","correct":false,"visible":false},{"text":"Williams syndrome","correct":false,"visible":false},{"text":"Patau syndrome","correct":false,"visible":false}]},{"id":3547,"text":"What is the most common cause of right heart failure (RHF)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 530.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Orthopnea","correct":false,"visible":false},{"text":"Left heart failure (LHF)","correct":true,"visible":false},{"text":"Septal defects","correct":false,"visible":false},{"text":"Cor pulmonale","correct":false,"visible":false}]},{"id":3563,"text":"A patient presents with a complaint of exertional chest pain. Which of the following substances mediates this pain?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 539.","responses":[{"text":"Interleukin","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Serotonin","correct":false,"visible":false},{"text":"Histamine","correct":false,"visible":false},{"text":"Adenosine","correct":true,"visible":false}]},{"id":3564,"text":"What would be the most effective preventive measure in the population to decrease the risk of cardiac disease?","explanation":null,"reference":"Cardiovascular module, Community-medicine lecture slides, Topic: Role of diet and nutritional lifestyle modifications, Subtopic: Behavioural risk factors.","responses":[{"text":"Weight loss","correct":false,"visible":false},{"text":"Stress management","correct":false,"visible":false},{"text":"Management of hypertension","correct":false,"visible":false},{"text":"Increase physical activity","correct":false,"visible":false},{"text":"Dietary and lifestyle changes","correct":true,"visible":false}]},{"id":3580,"text":"A 65-year-old patient with a recent history of myocardial infarction presents with acute shortness of breath. On examination, he has a pansystolic murmur at the mitral area and an audible S3 heart sound. Bi-basilar inspiratory crackles are also heard on inspiration. Which of the following is the most likely diagnosis for this patient?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 460.","responses":[{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Pericarditis","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Mitral regurgitation","correct":true,"visible":false},{"text":"Aortic stenosis","correct":false,"visible":false}]},{"id":3593,"text":"Which of the following does not cause cor pulmonale?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 530.","responses":[{"text":"Chronic obstructive pulmonary disease (COPD)","correct":false,"visible":false},{"text":"Right heart failure secondary to left heart failure","correct":true,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false},{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3594,"text":"What is the mechanism of action of nitroglycerin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 263.","responses":[{"text":"Decrease both cAMP and cGMP","correct":false,"visible":false},{"text":"Increases cAMP","correct":false,"visible":false},{"text":"Decreases cGMP","correct":false,"visible":false},{"text":"Decreases cAMP","correct":false,"visible":false},{"text":"Increases cGMP","correct":true,"visible":false}]},{"id":3595,"text":"Which of the following agents is preferred in hypertensive emergencies?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 185.","responses":[{"text":"Sodium nitroprusside","correct":true,"visible":false},{"text":"Amiodarone","correct":false,"visible":false},{"text":"Clonidine","correct":false,"visible":false},{"text":"Diazoxide","correct":false,"visible":false},{"text":"Propranolol","correct":false,"visible":false}]},{"id":3597,"text":"A 2-year-old baby had congenital heart disease. Which syndrome is most commonly associated with congenital heart disease?","explanation":"**Down syndrome** is frequently associated with **congenital heart defects**, specifically atrioventricular septal defects. Nearly half of all children with Down syndrome have some form of congenital heart disease, making it the most common syndrome associated with such defects.\r\n\r\n\r\nKlinefelter syndrome is a chromosomal disorder, but it is not primarily associated with congenital heart disease.\r\n\r\nAlthough maternal rubella infection can lead to congenital heart disease, it is not a syndrome associated with a high frequency of such defects.\r\n\r\nWhile DiGeorge syndrome: syndrome can include heart defects, it is not as commonly associated with congenital heart disease as Down syndrome.","reference":"Cardiovascular module, Medicine lecture slides, Topic: A practical approach to congenital heart diseases, Subtopic: Risk factors.","responses":[{"text":"DiGeorge syndrome","correct":false,"visible":false},{"text":"Rubella syndrome","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Klinefelter syndrome","correct":false,"visible":false},{"text":"Down syndrome","correct":true,"visible":false}]},{"id":3598,"text":"Which of the following is true regarding atrial septal defect?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 77.","responses":[{"text":"It is the commonest congenital cardiac anomaly","correct":false,"visible":false},{"text":"It usually causes death before puberty if untreated","correct":false,"visible":false},{"text":"It is associated with trisomy 21","correct":true,"visible":false},{"text":"It is twice as common in males as compared to females","correct":false,"visible":false},{"text":"It does not lead to pulmonary hypertension","correct":false,"visible":false}]},{"id":3601,"text":"'Sign of 3' is a feature of which congenital disease of the heart?","explanation":"In **coarctation of the aorta**, classic radiographic findings can include a **\"3 sign\"** or \"figure 3 sign,\" which is due to pre- and post-stenotic dilatation of the aorta and indentation at the site of coarctation. This is often seen on a chest X-ray and can help in the diagnosis.\r\n\r\n\r\nTetralogy of Fallot is characterized on the chest X-ray as a \"boot-shaped\" heart, not the \"3 sign.\"\r\nPersistent truncus arteriosus involves a single arterial vessel coming out of the heart and does not produce a \"3 sign\" on imaging.\r\nAtrial septal defect and patent ductus arteriosus do have any specific radiographic findings.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 534.","responses":[{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Persistent truncus arteriosus","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":false,"visible":false},{"text":"Tetralogy of Fallot","correct":false,"visible":false},{"text":"Coarctation of aorta","correct":true,"visible":false}]},{"id":3603,"text":"A 48-year-old female presents to the emergency department with a bleeding nose and high blood pressure. Upon physical examination, hypertension in upper limbs but hypotension in lower limbs is noticed. Which of the following conditions has the patient developed?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 78.","responses":[{"text":"Infundibular pulmonary stenosis","correct":false,"visible":false},{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":false,"visible":false},{"text":"Tetralogy of Fallot","correct":false,"visible":false},{"text":"Coarctation of aorta","correct":true,"visible":false}]},{"id":3605,"text":"A 2-month-old baby presents with poor feeding and respiratory distress. Physical examination reveals normal pulses, but a pansystolic murmur is heard at the left sternal angle. The baby is also tachypneic, with hepatomegaly and marked cardiomegaly. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 460.","responses":[{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Transposition of the great arteries","correct":false,"visible":false},{"text":"Tetralogy of Fallot","correct":false,"visible":false},{"text":"Ventricular septal defect","correct":true,"visible":false},{"text":"Truncus arteriosus","correct":false,"visible":false}]},{"id":3607,"text":"A 5-year-old child is found to have a pansystolic murmur that is best heard at the left sternal edge and radiates all over the precordium. Which of the complications is most likely to develop in this child?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 460.\r\n\r\n\r\n\r\n2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 535.","responses":[{"text":"Aortic dissection","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":false,"visible":false},{"text":"Systemic hypertension","correct":false,"visible":false},{"text":"Pulmonary hypertension","correct":true,"visible":false},{"text":"High grade fever","correct":false,"visible":false}]},{"id":3609,"text":"A 30-year-old patient is identified with hypertension in his upper extremities and hypotension in his lower extremities. His X-ray shows notches on his ribs. What is the most likely condition ssociated with his presentations?","explanation":"**Coarctation of the aorta** is characterized by a narrowing of the aorta, which leads to a pressure gradient above and below the site of narrowing. This results in increased blood pressure in the upper extremities and decreased pressure in the lower extremities. **Rib notching** is due to collateral circulation that develops to bypass the narrow segment, causing erosion of the inferior aspect of the ribs.\r\n\r\n\r\nTetralogy of Fallot typically presents with cyanosis and a \"boot-shaped\" heart on X-ray, not with differential blood pressures in the upper and lower extremities.\r\n\r\nAtrial septal defect involves an opening between the atria and usually presents with signs of right-sided heart overload, not the symptoms described.\r\n\r\nInfundibular pulmonary stenosis causes obstruction between the right ventricle and the pulmonary artery but would not cause the symptoms described.\r\n\r\nPatent ductus arteriosus involves a duct between the aorta and the pulmonary artery remaining open after birth, leading to a \"machinery\" murmur and potential heart failure but not the symptoms described.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 78.","responses":[{"text":"Coarctation of the aorta","correct":true,"visible":false},{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Tetralogy of Fallot","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":false,"visible":false},{"text":"Infundibular pulmonary stenosis","correct":false,"visible":false}]},{"id":3610,"text":"Which of the following diseases does not have left to right shunt, hence does not cause Eisenmenger syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 533, 535.","responses":[{"text":"Tetralogy of Fallot","correct":true,"visible":false},{"text":"Ventricular septal defect (VSD)","correct":false,"visible":false},{"text":"Atrial septal defect (ASD)","correct":false,"visible":false},{"text":"Atrioventricular defect (AVSD)","correct":false,"visible":false},{"text":"Patent ductus arteriosus (PDA)","correct":false,"visible":false}]},{"id":3615,"text":"What is the mechanism of action of heparin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 276-277.","responses":[{"text":"Catalyzes the binding of antithrombin III","correct":true,"visible":false},{"text":"Blocks protein kinase A","correct":false,"visible":false},{"text":"Increases cGMP","correct":false,"visible":false},{"text":"Increases cAMP","correct":false,"visible":false},{"text":"Decreases hepatic synthesis of vitamin K dependent factors","correct":false,"visible":false}]},{"id":3617,"text":"What is the appearance of a tissue that has undergone myocardial infarction (MI) 8 hours ago?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 544.","responses":[{"text":"Red and swollen with early necrosis","correct":true,"visible":false},{"text":"Coagulation necrosis","correct":false,"visible":false},{"text":"Scar tissue","correct":false,"visible":false},{"text":"Tissue with neutrophil infiltrate","correct":false,"visible":false},{"text":"Gray-white scar","correct":false,"visible":false}]},{"id":3618,"text":"What is the time taken by the myocardial infarction to complete scarring?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 544.","responses":[{"text":"1 month","correct":false,"visible":false},{"text":"3 weeks","correct":false,"visible":false},{"text":"14 weeks","correct":false,"visible":false},{"text":"2 months","correct":true,"visible":false},{"text":"12 days","correct":false,"visible":false}]},{"id":3623,"text":"Which of the following congenital defect causes reversal of the shunt (from left to right to right to left) and hence Eisenmenger syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 535.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Large patent ductus arteriosus (PDA)","correct":true,"visible":false},{"text":"Tricuspid atresia","correct":false,"visible":false},{"text":"Coarctation of the aorta","correct":false,"visible":false},{"text":"Transpositions of great vessels","correct":false,"visible":false}]},{"id":3632,"text":"Which of the following correctly describes atrial septal defect?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 533-534.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"A congenital cyanotic defect between left and right atria","correct":false,"visible":false},{"text":"A congenital non-cyanotic defect between left and right ventricles","correct":false,"visible":false},{"text":"A congenital non-cyanotic defect between left and right atria","correct":true,"visible":false},{"text":"A congenital cyanotic defect between left and right ventricles","correct":false,"visible":false}]},{"id":3636,"text":"A 41-year-old man is diagnosed with congenital heart disease. He had no symptoms early in his life. What could be the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 534.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Ventrcular septal defect","correct":false,"visible":false},{"text":"Atrial septal defect","correct":true,"visible":false},{"text":"Tetralogy of Fallot","correct":false,"visible":false},{"text":"Patent ductus arteriosus","correct":false,"visible":false}]},{"id":3643,"text":"A ventricular septal defect is most commonly associated with which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 535.","responses":[{"text":"Aortic regurgitation","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Teratology of Fallot","correct":true,"visible":false},{"text":"Mitral regurgitation","correct":false,"visible":false}]},{"id":3663,"text":"Nitroglycerin is contraindicated in which of the following conditions?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 200.","responses":[{"text":"Arterial constriction","correct":false,"visible":false},{"text":"Hypertensive emergency","correct":false,"visible":false},{"text":"Raised intracranial pressure","correct":true,"visible":false},{"text":"Renal artery stenosis","correct":false,"visible":false},{"text":"Headache","correct":false,"visible":false}]},{"id":3664,"text":"Pulmonary hypertension is caused by which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 81.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Mitral stenosis","correct":true,"visible":false},{"text":"Tricuspid atresia","correct":false,"visible":false},{"text":"Tricuspid stenosis","correct":false,"visible":false},{"text":"Pulmonic stenosis","correct":false,"visible":false}]},{"id":3666,"text":"What is the most common cause of mitral valve prolapse?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 556.","responses":[{"text":"Hypertrophic cardiomyopathy","correct":false,"visible":false},{"text":"Marfan syndrome","correct":false,"visible":false},{"text":"Tricuspid valve prolapse","correct":false,"visible":false},{"text":"Hydropic degeneration","correct":false,"visible":false},{"text":"Myxomatous degeneration","correct":true,"visible":false}]},{"id":3669,"text":"Which of the following food items is rich in saturated fats?","explanation":null,"reference":"Forouhi NG, Krauss RM, Taubes G, Willett W. Dietary fat and cardiometabolic health: evidence, controversies, and consensus for guidance. The BMJ. Published June 13, 2018. Accessed June 18, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6053258/","responses":[{"text":"Yoghurt","correct":false,"visible":false},{"text":"Animal fat","correct":true,"visible":false},{"text":"Eggs","correct":false,"visible":false},{"text":"Canola oil","correct":false,"visible":false},{"text":"Spinach","correct":false,"visible":false}]},{"id":3685,"text":"What is the most common cause of abdominal aortic aneurysms?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 502.","responses":[{"text":"Trauma","correct":false,"visible":false},{"text":"Vascular wall abnormalities","correct":false,"visible":false},{"text":"Atherosclerosis","correct":true,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Vasculitis","correct":false,"visible":false}]},{"id":3694,"text":"What is the name of the point which adjoins the QRS complex and the ST segment?","explanation":"The **J point** is the junction of the termination of the QRS complex and the beginning of the ST segment on the electrocardiogram (ECG). It's important in diagnosing and assessing various cardiac conditions, including myocardial infarctions and various types of cardiac arrhythmias.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 153.","responses":[{"text":"A point","correct":false,"visible":false},{"text":"X descent point","correct":false,"visible":false},{"text":"X point","correct":false,"visible":false},{"text":"J point","correct":true,"visible":false},{"text":"C wave point","correct":false,"visible":false}]},{"id":3697,"text":"A patient presents with chest pain that increases on inspiration and lying down and is relieved when leaning forward. What is the most likely pathology?","explanation":null,"reference":"1) Ismail TF. Acute pericarditis: Update on diagnosis and management. Clin Med (Lond) [Internet]. 2020 Jan [cited 2022 Jun 21];20(1):48–51. Available from: https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6964178/\r\n\r\n\r\n2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 542.","responses":[{"text":"Bacterial myocarditis","correct":false,"visible":false},{"text":"Acute pericarditis","correct":true,"visible":false},{"text":"Cardiac tamponade","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Bacterial endocarditis","correct":false,"visible":false}]},{"id":3748,"text":"Concurrent administration of quinidine and digoxin results in drug-drug interaction. How does quinidine interact with digoxin?","explanation":null,"reference":"Bigger JT, Leahey EB. Quinidine and digoxin. An important interaction. Drugs. Published September 1982. https://pubmed.ncbi.nlm.nih.gov/6751790","responses":[{"text":"Synergistic effect on myocardium","correct":false,"visible":false},{"text":"Inhibits the metabolism of digoxin","correct":false,"visible":false},{"text":"Antagonized the effect of digoxin on the A-V node","correct":false,"visible":false},{"text":"Increased serum concentration of digoxin","correct":true,"visible":false},{"text":"Decreased the absorption of digoxin in GIT","correct":false,"visible":false}]},{"id":3749,"text":"What mechanism of action allows the use of digoxin in atrial fibrillation?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 217, 223.","responses":[{"text":"Slows down AV node conduction","correct":true,"visible":false},{"text":"Speeds up AV node conduction","correct":false,"visible":false},{"text":"Increases SA node firing","correct":false,"visible":false},{"text":"Increases myocardium contractility","correct":false,"visible":false},{"text":"Decreases myocardium contractility","correct":false,"visible":false}]},{"id":3752,"text":"What type of cells are anitschkow cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 558.","responses":[{"text":"Eosinophils","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false},{"text":"T-lymphocytes","correct":false,"visible":false},{"text":"B-lymphocytes","correct":false,"visible":false},{"text":"Erythrocytes","correct":false,"visible":false}]},{"id":3754,"text":"How many total set of valves does a normal heart contain?","explanation":null,"reference":"Hinton RB, Yutzey KE. Heart valve structure and function in development and disease. Annual review of physiology. Published 2011. Accessed June 21, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4209403/","responses":[{"text":"5","correct":false,"visible":false},{"text":"2","correct":false,"visible":false},{"text":"3","correct":false,"visible":false},{"text":"1","correct":false,"visible":false},{"text":"4","correct":true,"visible":false}]},{"id":3760,"text":"Suppurative pericarditis with subsequent scarring leads to which of the following?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 575. (2) Yacoub M, Quintanilla Rodriguez BS, Mahajan K. Constrictive-effusive pericarditis. In: StatPearls. StatPearls Publishing; 2022. Accessed June 18, 2022. http://www.ncbi.nlm.nih.gov/books/NBK519579/","responses":[{"text":"Serous pericarditis","correct":false,"visible":false},{"text":"Fibrinous pericarditis","correct":false,"visible":false},{"text":"Adhesive mediastinopericarditis","correct":false,"visible":false},{"text":"Constrictive pericarditis","correct":true,"visible":false},{"text":"Myopericarditis","correct":false,"visible":false}]},{"id":3761,"text":"Atrial fibrillation most commonly occurs as a complication of which of the following?","explanation":null,"reference":"1) Ogunsua AA, Shaikh AY, Ahmed M, McManus DD. Atrial fibrillation and hypertension: mechanistic, epidemiologic, and treatment parallels. Methodist DeBakey Cardiovascular Journal. Published 2015. Accessed June 24, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4814009/\r\n\r\n2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 471.","responses":[{"text":"Hypertrophy","correct":false,"visible":false},{"text":"Myocardial infarction","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Hypertension","correct":true,"visible":false}]},{"id":3762,"text":"A 50-year-old lady with a known case of rheumatoid arthritis for the last 15 years, develops lethargy, exertional dyspnea, collapsing radial pulse, visible nail bed, and carotid pulsation in the neck. On chest auscultation, high pitched early diastolic murmur is heard. What is the most likely valvular abnormality she is suffering from?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 300.","responses":[{"text":"Aortic stenosis","correct":false,"visible":false},{"text":"Mitral regurgitation","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Aortic regurgitation","correct":true,"visible":false}]},{"id":3763,"text":"Which of the following organisms is involved in the pathogenesis of rheumatic fever?","explanation":null,"reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 114.","responses":[{"text":"Streptococcus viridians","correct":false,"visible":false},{"text":"Streptococcus agalactiae","correct":false,"visible":false},{"text":"Streptococcus pyogenes","correct":true,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false}]},{"id":3804,"text":"Which of the following is true for mitral stenosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 459.","responses":[{"text":"Opening snap sound","correct":true,"visible":false},{"text":"Mid-diastolic murmur","correct":false,"visible":false},{"text":"Machine like murmur","correct":false,"visible":false},{"text":"Mid-systolic murmur","correct":false,"visible":false},{"text":"Holosystolic murmur","correct":false,"visible":false}]},{"id":3805,"text":"Which of the following statements is incorrect?","explanation":null,"reference":"1) Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 54.\r\n\r\n2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 193, 239-240.","responses":[{"text":"The inferior border of the heart extends from the 6th right costal cartilage to the apex","correct":false,"visible":false},{"text":"Apex beat is palpated on left intercostal space lateral to mid clavicular line","correct":true,"visible":false},{"text":"Mitral sounds are best heard at apex","correct":false,"visible":false},{"text":"Apex beat is palpated on left intercostal space medial to mid clavicular line","correct":false,"visible":false},{"text":"The left border of the heart is formed by the left ventricle","correct":false,"visible":false}]},{"id":3808,"text":"Which of the following will lead to an apex beat auscultated lateral to midclavicular line in the 6th intercostal space?","explanation":null,"reference":"Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 54-55.","responses":[{"text":"Right ventricle dilatation","correct":false,"visible":false},{"text":"Right atrium dilatation","correct":false,"visible":false},{"text":"Left ventricle dilatation","correct":true,"visible":false},{"text":"Left ventricle hypoplasia","correct":false,"visible":false},{"text":"Left atrium hypoplasia","correct":false,"visible":false}]},{"id":3809,"text":"Which of the following findings would indicate a high-risk factor prediction while performing the exercise tolerance test (ETT)?","explanation":"**ST-segment depression of 2 mm or more in inferior leads** during exercise tolerance testing is considered a strong indicator of myocardial ischemia and is a **high-risk factor for coronary artery disease**. This finding typically warrants further diagnostic investigations and possibly therapeutic interventions.\r\n\r\n\r\nA small drop in diastolic blood pressure is usually not considered a high-risk factor during ETT.\r\n\r\nUpsloping ST depressions are generally considered to be less specific for ischemia than horizontal or downsloping ST depressions.\r\n\r\nA drop in systolic BP could be concerning, but a 5 mm Hg drop is usually not considered a high-risk feature.\r\n\r\n ST elevation can be a concerning sign, but it usually needs to be evaluated in the context of other clinical and ECG findings. Isolated 1 mm ST elevation in V2-V6 without other corroborating evidence is not usually considered a high-risk factor prediction in ETT.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 449.","responses":[{"text":"3 mm Hg drop in diastolic blood pressure","correct":false,"visible":false},{"text":"5 mm Hg drop in systolic blood pressure","correct":false,"visible":false},{"text":"1 mm ST elevation in V2-V6","correct":false,"visible":false},{"text":"2 mm ST depression in inferior leads","correct":true,"visible":false},{"text":"Upsloping ST depression of 3 mm in V2-V6","correct":false,"visible":false}]},{"id":3810,"text":"A patient has a systolic murmur in the aortic area. Which of the following is a character of this murmur?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 459-460.\r\n2) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 300.","responses":[{"text":"Crescendo","correct":false,"visible":false},{"text":"Diamond-shaped","correct":true,"visible":false},{"text":"Holosystolic","correct":false,"visible":false},{"text":"Triangular","correct":false,"visible":false},{"text":"Decrescendo","correct":false,"visible":false}]},{"id":3811,"text":"Which of the following conditions will show a crescendo-decrescendo murmur?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 459-460.\r\n2) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 300.","responses":[{"text":"Mitral regurgitation (MR)","correct":false,"visible":false},{"text":"Atrial septal defect (ASD)","correct":false,"visible":false},{"text":"Ventricular septal defect (VSD)","correct":false,"visible":false},{"text":"Aortic stenosis (AS)","correct":true,"visible":false},{"text":"Hypertrophic cardiomyopathy (HCM)","correct":false,"visible":false}]},{"id":3812,"text":"A 46-year-old male patient is being given an anti-arrhythmic drug post-myocardial infarction to suppress premature ventricular contractions. As a result, he develops seizures. Which of the following conditions has he developed?","explanation":null,"reference":"1) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 253.\r\n\r\n\r\n2) Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 330.","responses":[{"text":"Ventricular tachycardia","correct":false,"visible":false},{"text":"Ventricular asystole","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":false,"visible":false},{"text":"Atropine toxicity","correct":false,"visible":false},{"text":"Lidocaine toxicity","correct":true,"visible":false}]},{"id":3813,"text":"Which of the following anti-arrhythmic drugs causes constipation as a side effect?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 332.","responses":[{"text":"Atenolol","correct":false,"visible":false},{"text":"Quinidine","correct":false,"visible":false},{"text":"Lidocaine","correct":false,"visible":false},{"text":"Propanolol","correct":false,"visible":false},{"text":"Verapamil","correct":true,"visible":false}]},{"id":3814,"text":"Which one of the following is a potassium channel activator?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 186.","responses":[{"text":"Metoprolol","correct":false,"visible":false},{"text":"Clonidine","correct":false,"visible":false},{"text":"Methyldopa","correct":false,"visible":false},{"text":"Diazoxide","correct":true,"visible":false},{"text":"Tolbutamide","correct":false,"visible":false}]},{"id":3815,"text":"Which of the following drugs is contraindicated in variant angina?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 208.","responses":[{"text":"Diltiazem","correct":false,"visible":false},{"text":"Verapamil","correct":false,"visible":false},{"text":"Beta-blockers","correct":true,"visible":false},{"text":"Nifedipine","correct":false,"visible":false},{"text":"Nitroglycerine","correct":false,"visible":false}]},{"id":3850,"text":"Which of the following is preferably given for relief in acute variant angina?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 108.","responses":[{"text":"Propanolol","correct":false,"visible":false},{"text":"Diltiazem","correct":false,"visible":false},{"text":"Nifedipine","correct":true,"visible":false},{"text":"Isosorbide","correct":false,"visible":false},{"text":"Atenolol","correct":false,"visible":false}]},{"id":3851,"text":"Which of the following is an adverse effect of procainamide?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 238.","responses":[{"text":"Anemia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":false,"visible":false},{"text":"Torsades de pointes","correct":true,"visible":false},{"text":"Hypertension","correct":false,"visible":false}]},{"id":3852,"text":"Procainamide is used for which of the following?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 239.","responses":[{"text":"Aortic stenosis","correct":false,"visible":false},{"text":"Right-sided heart failure","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":true,"visible":false},{"text":"Left-sided heart failure","correct":false,"visible":false},{"text":"Left ventricular hypertrophy","correct":false,"visible":false}]},{"id":3853,"text":"Which of the following class of drugs operates by activating guanylate cyclase and increasing cGMP?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 263.","responses":[{"text":"Ranolazine","correct":false,"visible":false},{"text":"Digoxine","correct":false,"visible":false},{"text":"Milrinone","correct":false,"visible":false},{"text":"Nitrates","correct":true,"visible":false},{"text":"Amlodipine","correct":false,"visible":false}]},{"id":3854,"text":"A patient taking a class of antihypertensives complains about side effects of severe dry cough. Which of the following drugs is causing the dry cough?","explanation":"**Captopril** belongs to the class of angiotensin-converting enzyme (ACE) inhibitors, which are well-known for causing a **persistent dry cough** as a side effect. This cough can be severe enough to warrant discontinuation of the medication, and it typically resolves after stopping the drug.\r\n\r\n\r\nPropanolol and atenolol are beta-blockers and are generally not associated with causing a dry cough.\r\n\r\nVerapamil and diltiazem are calcium channel blockers and usually cause constipation as a side effect.","reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 187-188, 210.","responses":[{"text":"Atenolol","correct":false,"visible":false},{"text":"Diltiazem","correct":false,"visible":false},{"text":"Verapamil","correct":false,"visible":false},{"text":"Captopril","correct":true,"visible":false},{"text":"Propanolol","correct":false,"visible":false}]},{"id":3855,"text":"Which of these drugs has a moderate blocking effect on phase 0 of the cardiac action potential?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 251.","responses":[{"text":"Lidocaine","correct":false,"visible":false},{"text":"Atenolol","correct":false,"visible":false},{"text":"Flecainide","correct":false,"visible":false},{"text":"Amiodarone","correct":false,"visible":false},{"text":"Quinidine","correct":true,"visible":false}]},{"id":3856,"text":"Which of the following is the neurological disorder as a result of rheumatic fever?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 559.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Arthritis","correct":false,"visible":false},{"text":"Painless lumps (nodules)","correct":false,"visible":false},{"text":"Sydenham chorea (SC)","correct":true,"visible":false},{"text":"Erythema marginatum","correct":false,"visible":false}]},{"id":3857,"text":"Which of the following drugs is not contraindicated in pregnancy?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 214.","responses":[{"text":"Propranolol","correct":false,"visible":false},{"text":"Captopril","correct":false,"visible":false},{"text":"Atenolol","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Methyldopa","correct":true,"visible":false}]},{"id":3858,"text":"Which of the following represents Duke's major criteria?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 529.","responses":[{"text":"One blood culture positive and echocardiographic changes","correct":false,"visible":false},{"text":"Two blood cultures positive and echocardiographic changes","correct":true,"visible":false},{"text":"Echocardiographic changes only","correct":false,"visible":false},{"text":"Fever and immunologic phenomena","correct":false,"visible":false},{"text":"Fever and predisposing heart condition","correct":false,"visible":false}]},{"id":3859,"text":"Which of the following is the characteristic cell of rheumatic fever?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 558.","responses":[{"text":"Aschoff bodies","correct":true,"visible":false},{"text":"Epithelioid cells","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Charcot Leyden crystals","correct":false,"visible":false},{"text":"Curschmann spirals","correct":false,"visible":false}]},{"id":3860,"text":"Which class of drugs are 3-hydroxy-3-methyl-glutaryl-coenzyme A reductase (HMG CoA reductase) inhibitors?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 632.","responses":[{"text":"Nitrates","correct":false,"visible":false},{"text":"Statins","correct":true,"visible":false},{"text":"Fibrates","correct":false,"visible":false},{"text":"Bile acid sequestrants","correct":false,"visible":false},{"text":"Niacin","correct":false,"visible":false}]},{"id":3861,"text":"Which of the following is an alpha-2 agonist?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 139.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Terbutaline","correct":false,"visible":false},{"text":"Phenylephrine","correct":false,"visible":false},{"text":"Clonidine","correct":true,"visible":false},{"text":"Dobutamide","correct":false,"visible":false}]},{"id":3862,"text":"Which of the following drugs converts plasminogen to plasmin?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 619.","responses":[{"text":"Alteplase","correct":true,"visible":false},{"text":"Aminocaproic acid","correct":false,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Streptokinase","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false}]},{"id":3864,"text":"Which of the following correctly defines idiosyncrasy?","explanation":"**Idiosyncratic** reactions are **unpredictable** and **not dose-dependent**. They are **rare** adverse effects that occur **sporadically** among the population, often even at low dosages. These reactions are usually due to genetic differences in metabolism or immune response and are difficult to foresee.\r\n\r\n---\r\n\r\n\r\nWidespread allergic response is an exaggerated immune reaction to a drug but is not idiosyncratic.\r\n\r\nAdverse effects that generally occur in the majority of the population would be common side effects, not idiosyncrasies.\r\n\r\nAn exaggerated immune response can be an allergic reaction but is not specifically what is meant by idiosyncrasy.","reference":"Uetrecht J, Naisbitt DJ. Idiosyncratic adverse drug reactions: current concepts. Pharmacological Reviews. Published April 2013. Accessed June 23, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3639727/","responses":[{"text":"Adverse effects that generally occur in the majority of population","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Adverse effects that are infrequent and sporadically seen among the population even with low dosages","correct":true,"visible":false},{"text":"Exaggerated immune response","correct":false,"visible":false},{"text":"Widespread allergic response","correct":false,"visible":false}]},{"id":3866,"text":"Which of the following antihypertensives is safe to use in pregnancy?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 214.","responses":[{"text":"Benazepril","correct":false,"visible":false},{"text":"Atenolol","correct":false,"visible":false},{"text":"Methyldopa","correct":true,"visible":false},{"text":"Metolazone","correct":false,"visible":false},{"text":"Captopril","correct":false,"visible":false}]},{"id":3871,"text":"Which of the following is correct about mitral valve prolapse?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 556.","responses":[{"text":"Commonly associated with apical chest pain","correct":false,"visible":false},{"text":"Is a condition associated with high risk of embolic stroke or TIA","correct":false,"visible":false},{"text":"Produces ejection click and early systolic murmur","correct":false,"visible":false},{"text":"Is caused by congenital anomalies or degenerative myxomatous changes","correct":true,"visible":false},{"text":"Is associated with a variety of lethal arrhythmias","correct":false,"visible":false}]},{"id":3874,"text":"Which of the following is incorrect regarding a typical second heart sound?","explanation":null,"reference":"Felner JM. The second heart sound. In: Walker HK, Hall WD, Hurst JW, eds. Clinical Methods: The History, Physical, and Laboratory Examinations. 3rd ed. Butterworths; 1990. Accessed June 19, 2022. http://www.ncbi.nlm.nih.gov/books/NBK341/","responses":[{"text":"Helps in diagnosis of atrial septal defect","correct":false,"visible":false},{"text":"Best heard with the bell of stethoscope","correct":true,"visible":false},{"text":"Quantifies pulmonary pressure","correct":false,"visible":false},{"text":"Best heard in 2nd left intercostal space","correct":false,"visible":false},{"text":"Normally it splits during inspiration","correct":false,"visible":false}]},{"id":3882,"text":"Which of the following is the main indication for coronary artery bypass graft (CABG)?","explanation":null,"reference":"Bachar BJ, Manna B. Coronary artery bypass graft. In: StatPearls. StatPearls Publishing; 2022. Accessed June 23, 2022. http://www.ncbi.nlm.nih.gov/books/NBK507836/","responses":[{"text":"Single vessel disease","correct":false,"visible":false},{"text":"Three-vessel disease","correct":true,"visible":false},{"text":"Double-vessel disease","correct":false,"visible":false},{"text":"Aortic dissection","correct":false,"visible":false},{"text":"Stable angina","correct":false,"visible":false}]},{"id":3890,"text":"Which of the following is a side effect of angiotensin-converting enzyme (ACE) inhibitors?","explanation":null,"reference":"Goyal A, Cusick AS, Thielemier B. Ace inhibitors. In: StatPearls. StatPearls Publishing; 2023. Accessed August 15, 2023. http://www.ncbi.nlm.nih.gov/books/NBK430896/","responses":[{"text":"Renal artery stenosis","correct":false,"visible":false},{"text":"Hypokalemia","correct":false,"visible":false},{"text":"Agranulocytosis","correct":true,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Proteinuria","correct":false,"visible":false}]},{"id":3891,"text":"Which of the following is the most common cause of reversed splitting of S2?","explanation":null,"reference":"Felner JM. The second heart sound. In: Walker HK, Hall WD, Hurst JW, eds. Clinical Methods: The History, Physical, and Laboratory Examinations. 3rd ed. Butterworths; 1990. Accessed June 23, 2022. http://www.ncbi.nlm.nih.gov/books/NBK341/","responses":[{"text":"Severe aortic stenosis","correct":false,"visible":false},{"text":"Right bundle branch block","correct":false,"visible":false},{"text":"Hypertrophic obstructive cardiomyopathy","correct":false,"visible":false},{"text":"Right ventricular branch block","correct":false,"visible":false},{"text":"Left bundle branch block","correct":true,"visible":false}]},{"id":3892,"text":"Which vasculitis involves the aorta?","explanation":"**Takayasu disease**, also known as Takayasu arteritis, predominantly affects **large vessels**, including the **aorta and its main branches**. It is most commonly seen in young women and can lead to symptoms such as arm claudication, decreased pulses, and vascular bruits.\r\n\r\n---\r\n\r\nPolyarteritis nodosa typically involves medium-sized arteries and does not generally affect the aorta.\r\n\r\nBehcet disease is a multisystem vasculitis but does not primarily involve the aorta.\r\n\r\nGiant cell arteritis affects large and medium-sized vessels, such as the temporal artery, but it generally does not involve the aorta.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 65.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Takayasu disease","correct":true,"visible":false},{"text":"Giant cell arteritis","correct":false,"visible":false},{"text":"Behcet disease","correct":false,"visible":false},{"text":"Polyarteritis nodosa","correct":false,"visible":false}]},{"id":3893,"text":"Which kind of cells form the foam cells?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 62.","responses":[{"text":"Dendritic cells","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false},{"text":"Eosinophils","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false},{"text":"Histiocytes","correct":false,"visible":false}]},{"id":3902,"text":"In which of the following is the sinoatrial node present?","explanation":"The **sinoatrial (SA) node** is located in the **right atrium** near the entrance of the superior vena cava. It serves as the primary pacemaker of the heart, initiating the electrical impulses that set the rate and rhythm of cardiac contractions.","reference":"Kashou AH, Basit H, Chhabra L. Physiology, sinoatrial node. In: StatPearls. StatPearls Publishing; 2022. Accessed June 23, 2022. http://www.ncbi.nlm.nih.gov/books/NBK459238/","responses":[{"text":"Right atrium","correct":true,"visible":false},{"text":"Right ventricle","correct":false,"visible":false},{"text":"Left ventricle","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Left atrium","correct":false,"visible":false}]},{"id":3903,"text":"A 46-year-old woman suffering from obesity is traveling from Pakistan to USA. She starts experiencing shortness of breath. Which of the following could be a likely reason?","explanation":"**Pulmonary embolism** is a common and potentially fatal condition. In the context of a **long flight** (prolonged immobility) and **obesity** (both risk factors for deep vein thrombosis and subsequent pulmonary embolism), the symptoms of acute shortness of breath would most likely point towards a pulmonary embolism.\r\n\r\n---\r\n\r\nAAlthough severe, aortic dissection is generally characterized by intense tearing pain in the chest or back rather than isolated shortness of breath. It is also less likely than a pulmonary embolism in the context of long travel and obesity.\r\n\r\nPericarditis usually causes chest pain that is relieved by sitting forward, and is less likely to present acutely with shortness of breath alone in an otherwise asymptomatic person.\r\n\r\nAcute coronary syndrome rypically presents with chest pain, pressure, or discomfort rather than isolated shortness of breath. Also, it is less likely in the context of her travel history.\r\nHyperlipidemia is a chronic condition that wouldn't cause acute symptoms like shortness of breath.","reference":"1) Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 42.\r\n\r\n2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 558.\r\n\r\n\r\n3) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 698.","responses":[{"text":"Pericarditis","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":true,"visible":false},{"text":"Hyperlipidemia","correct":false,"visible":false},{"text":"Aortic dissection","correct":false,"visible":false},{"text":"Acute coronary syndrome","correct":false,"visible":false}]},{"id":3904,"text":"What is the length of the PR interval?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 137.","responses":[{"text":"0.2 s","correct":true,"visible":false},{"text":"0.1 s","correct":false,"visible":false},{"text":"0.5 s","correct":false,"visible":false},{"text":"0.4 s","correct":false,"visible":false},{"text":"0.3 s","correct":false,"visible":false}]},{"id":3905,"text":"Which of the following is increased in tuberculous pericardial effusions?","explanation":null,"reference":"Tuberculous pericarditis - an overview | sciencedirect topics. Accessed June 24, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/tuberculous-pericarditis","responses":[{"text":"Monocytes","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Lymphocytes","correct":true,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Eosinophils","correct":false,"visible":false}]},{"id":3906,"text":"Anitschkow cells are seen in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 558.","responses":[{"text":"Rheumatic pancarditis","correct":true,"visible":false},{"text":"Constrictive pericarditis","correct":false,"visible":false},{"text":"Rheumatic endocarditis","correct":false,"visible":false},{"text":"Infective endocarditis","correct":false,"visible":false},{"text":"Myocardial infarction","correct":false,"visible":false}]},{"id":3907,"text":"Which of the following is the most common cause of atrial fibrillation?","explanation":null,"reference":"1) Ogunsua AA, Shaikh AY, Ahmed M, McManus DD. Atrial fibrillation and hypertension: mechanistic, epidemiologic, and treatment parallels. Methodist DeBakey Cardiovascular Journal. Published 2015. Accessed June 24, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4814009/ \r\n\r\n2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 471.","responses":[{"text":"Myocardial infarction","correct":false,"visible":false},{"text":"Hypertension","correct":true,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false}]},{"id":3909,"text":"The Jones criteria is used to diagnose which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 559.","responses":[{"text":"Pericarditis","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Myocardial infarction","correct":false,"visible":false},{"text":"Rheumatic fever","correct":true,"visible":false},{"text":"Endocarditis","correct":false,"visible":false}]},{"id":3911,"text":"Which of the following leads to constrictive cardiomyopathy in transfusion dependent thalassemia?","explanation":"**Hemochromatosis** occurs due to iron overload, which is a common complication in transfusion-dependent thalassemia patients. The excess iron deposits in various tissues, including the heart, leading to fibrosis and subsequently, **constrictive cardiomyopathy**.\r\n\r\n---\r\n\r\nAnemia is indeed a feature of thalassemia but is not the direct cause of constrictive cardiomyopathy in this context.\r\n\r\nHypoxia, or lack of oxygen, could be a result of severe anemia or other conditions, but it is not the direct cause of constrictive cardiomyopathy in transfusion-dependent thalassemia.\r\n\r\nTachycardia refers to a fast heart rate and is not the direct cause of constrictive cardiomyopathy.\r\n\r\nWhile hemolysis may be a feature of thalassemia, it is not the cause of constrictive cardiomyopathy in this situation.","reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 318.","responses":[{"text":"Hemochromatosis","correct":true,"visible":false},{"text":"Anemia","correct":false,"visible":false},{"text":"Hemolysis","correct":false,"visible":false},{"text":"Hypoxia","correct":false,"visible":false},{"text":"Tachycardia","correct":false,"visible":false}]},{"id":3915,"text":"Which of the following commonly develops in the second trimester of pregnancy?","explanation":null,"reference":"Schaufelberger M. Cardiomyopathy and pregnancy. Heart. Published October 2019. Accessed June 23, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6839719/","responses":[{"text":"Restrictive cardiomyopathy","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Arrhythmogenic right ventricular cardiomyopathy (ARVC)","correct":false,"visible":false},{"text":"Dilated cardiomyopathy","correct":true,"visible":false},{"text":"Hypertrophic cardiomyopathy (HCM)","correct":false,"visible":false}]},{"id":3921,"text":"A 16-year-old soccer player collapses on the ground in the middle of a game from sudden heart failure. What is the most likely cause?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 552.","responses":[{"text":"Sinoatrial rhythm","correct":false,"visible":false},{"text":"Bundle branch block","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":false,"visible":false},{"text":"Ventricular fibrillation","correct":true,"visible":false},{"text":"Atrial tachycardia","correct":false,"visible":false}]},{"id":3923,"text":"Which of the following is used as diagnostic criteria for acute pericarditis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 542.","responses":[{"text":"Murmur on expiration","correct":false,"visible":false},{"text":"No pericardial effusion","correct":false,"visible":false},{"text":"Pericardial friction rub","correct":true,"visible":false},{"text":"Normal electrocardiogram findings","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3925,"text":"Which of the following is the major risk factor for aortic dissection?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 504.","responses":[{"text":"Atherosclerosis","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Aneurysm","correct":false,"visible":false},{"text":"Marfan syndrome","correct":false,"visible":false},{"text":"Hypertension","correct":true,"visible":false}]},{"id":3926,"text":"Which of the following is the most common primary tumor of the heart?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 575.","responses":[{"text":"Papillary fibroelastoma","correct":false,"visible":false},{"text":"Fibroma","correct":false,"visible":false},{"text":"Myxoma","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Rhabdomyoma","correct":false,"visible":false}]},{"id":3927,"text":"A 10-year-old child presents to the emergency with palpitations. On examination, he has an irregular radial pulse and a murmur best heard at the apex of the heart. Which of the following is the cause for the murmur?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 470-471, 517. \r\n2) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 81.","responses":[{"text":"Mitral valve regurgitation","correct":false,"visible":false},{"text":"Ventricular fibrillation","correct":false,"visible":false},{"text":"Heart block","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":true,"visible":false},{"text":"Pulmonic stenosis","correct":false,"visible":false}]},{"id":3928,"text":"What is the length of nasogastric tube that should be inserted during gastric lavage?","explanation":null,"reference":"Vij K. Textbook of Forensic Medicine and Toxicology Principles and Practice. 5th ed. Elsevier; 2011: 450.","responses":[{"text":"30 cm","correct":false,"visible":false},{"text":"35 cm","correct":false,"visible":false},{"text":"50 cm","correct":true,"visible":false},{"text":"40 cm","correct":false,"visible":false},{"text":"20 cm","correct":false,"visible":false}]},{"id":3929,"text":"Which of the following is the contraindication in the left bundle branch block (LBBB)?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 452.","responses":[{"text":"Thallium scan","correct":false,"visible":false},{"text":"CT angiography","correct":false,"visible":false},{"text":"Cardiac MRI","correct":false,"visible":false},{"text":"Dobutamine stress echo","correct":false,"visible":false},{"text":"Exercise stress testing (ETT)","correct":true,"visible":false}]},{"id":3930,"text":"Which of the following diseases is caused by genetic causes?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 569.","responses":[{"text":"Infective endocarditis","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Cor pulmonale","correct":false,"visible":false},{"text":"Hypertrophic cardiomyopathy","correct":true,"visible":false},{"text":"Carcinoid heart disease","correct":false,"visible":false}]},{"id":3931,"text":"Which of the following cardiac dysfunction is seen in restrictive cardiomyopathy?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 570.","responses":[{"text":"Systolic dysfunction","correct":false,"visible":false},{"text":"It has no effect on systolic or diastolic function of the heart","correct":false,"visible":false},{"text":"Diastolic dysfunction","correct":true,"visible":false},{"text":"Systolic dysfunction that converts to diastolic with increasing severity","correct":false,"visible":false},{"text":"Both systolic and diastolic dysfunction","correct":false,"visible":false}]},{"id":3932,"text":"What is the term used to describe an acid attack?","explanation":null,"reference":"Kaur N, Kumar A. Vitriolage (Vitriolism) - a medico-socio-legal review. Forensic Science, Medicine, and Pathology. Published September 2020. https://pubmed.ncbi.nlm.nih.gov/32304016/","responses":[{"text":"Corrosive attack","correct":false,"visible":false},{"text":"Grievous injury","correct":false,"visible":false},{"text":"Vitriolage","correct":true,"visible":false},{"text":"Sexual assault","correct":false,"visible":false},{"text":"Mounting injury","correct":false,"visible":false}]},{"id":3934,"text":"Which of the following is a major cause of restrictive cardiomyopathy?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 570.","responses":[{"text":"Tumors","correct":false,"visible":false},{"text":"Ventricular septal defect","correct":false,"visible":false},{"text":"Amyloidosis","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Myocarditis","correct":false,"visible":false}]},{"id":3936,"text":"What effect do somniferous poisons have?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 537.","responses":[{"text":"Hyperventilation","correct":false,"visible":false},{"text":"Diuresis","correct":false,"visible":false},{"text":"Hyperthermia","correct":false,"visible":false},{"text":"Sleep induction","correct":true,"visible":false},{"text":"Tachycardia","correct":false,"visible":false}]},{"id":3937,"text":"Which of the following is present in atherosclerotic plaque?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 498.","responses":[{"text":"Magnesium","correct":false,"visible":false},{"text":"Cholesterol","correct":true,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"HDL","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false}]},{"id":3939,"text":"Which of the following is not related to the causes of atherosclerosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 492-493.","responses":[{"text":"Smoking","correct":false,"visible":false},{"text":"Hypercholesterolemia","correct":false,"visible":false},{"text":"Increased low-density lipoprotein (LDL)","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Increased high-density lipoprotein (HDL)","correct":true,"visible":false}]},{"id":3940,"text":"Which of the following should not be used as an antidote for sulphuric acid?","explanation":null,"reference":"PubChem. Sodium bicarbonate. Accessed June 21, 2022. https://pubchem.ncbi.nlm.nih.gov/compound/516892","responses":[{"text":"Sodium bicarbonate","correct":true,"visible":false},{"text":"Limewater","correct":false,"visible":false},{"text":"All of these can be used","correct":false,"visible":false},{"text":"Magnesium oxide","correct":false,"visible":false},{"text":"Milk of magnesia","correct":false,"visible":false}]},{"id":3941,"text":"Saturated fatty acids increase the risk of which of the following?","explanation":null,"reference":"Briggs MA, Petersen KS, Kris-Etherton PM. Saturated fatty acids and cardiovascular disease: replacements for saturated fat to reduce cardiovascular risk. Healthcare (Basel, Switzerland). Published June 21, 2017. https://pubmed.ncbi.nlm.nih.gov/28635680/","responses":[{"text":"Malignancy","correct":false,"visible":false},{"text":"Cardiovascular disease","correct":true,"visible":false},{"text":"Stroke","correct":false,"visible":false},{"text":"Hemorrhage","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":3942,"text":"A person presents to the outpatient department with the complaint of increased blood pressure. On examination, his blood pressure is 160/100 mmHg, and is declared to have hypertension. What is the mean arterial pressure in this patient?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 294.","responses":[{"text":"120 mmHg","correct":true,"visible":false},{"text":"110 mmHg","correct":false,"visible":false},{"text":"150 mmHg","correct":false,"visible":false},{"text":"130 mmHg","correct":false,"visible":false},{"text":"90 mmHg","correct":false,"visible":false}]},{"id":3943,"text":"Which of the following signs confirms drowning?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 202.","responses":[{"text":"Cadaveric spasm","correct":false,"visible":false},{"text":"Distended lungs","correct":false,"visible":false},{"text":"Froth from mouth","correct":true,"visible":false},{"text":"Cutis anserina","correct":false,"visible":false},{"text":"Clenched fists","correct":false,"visible":false}]},{"id":3944,"text":"Which of the following is a pulseless disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 508.","responses":[{"text":"Aortic regurgitation","correct":false,"visible":false},{"text":"Tricuspid atresia","correct":false,"visible":false},{"text":"Atherosclerosis","correct":false,"visible":false},{"text":"Cardiomyopathy","correct":false,"visible":false},{"text":"Takayasu's arteritis","correct":true,"visible":false}]},{"id":3945,"text":"Which of the following is not a contraindication of gastric lavage?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 486-487.","responses":[{"text":"Carbolic acid","correct":true,"visible":false},{"text":"Unprotected airway","correct":false,"visible":false},{"text":"Hydrocarbon poisoning","correct":false,"visible":false},{"text":"Corrosive poisoning","correct":false,"visible":false},{"text":"Ingestion of sharp objects","correct":false,"visible":false}]},{"id":3946,"text":"Which of the following can cause ST segment depression?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 74.","responses":[{"text":"Pericarditis","correct":false,"visible":false},{"text":"Subendocardial ischemia","correct":true,"visible":false},{"text":"Myocardial infarction","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Prinzmetal angina","correct":false,"visible":false}]},{"id":3947,"text":"Which of the following is most likely to cause infectious endocarditis in an intravenous (IV) drug abuser?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 82.","responses":[{"text":"Streptococcus viridans","correct":false,"visible":false},{"text":"Staphylococcus saprophyticus","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":true,"visible":false},{"text":"Streptococcus bovis","correct":false,"visible":false},{"text":"Staphylococcus epidermidis","correct":false,"visible":false}]},{"id":3948,"text":"Hyperlipidemia is associated with which of the following?","explanation":null,"reference":"Hill MF, Bordoni B. Hyperlipidemia. In: StatPearls. StatPearls Publishing; 2022. Accessed June 24, 2022. http://www.ncbi.nlm.nih.gov/books/NBK559182","responses":[{"text":"Diabetes","correct":false,"visible":false},{"text":"Sedentary lifestyle","correct":false,"visible":false},{"text":"Obesity","correct":false,"visible":false},{"text":"High-fat diet","correct":false,"visible":false},{"text":"All of these","correct":true,"visible":false}]},{"id":3949,"text":"What is the name given to the poisons which act primarily on nervous system?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 466.","responses":[{"text":"Neurotoxins","correct":false,"visible":false},{"text":"Neurotic poisons","correct":true,"visible":false},{"text":"Peripheral nervous system toxins","correct":false,"visible":false},{"text":"Neural poisons","correct":false,"visible":false},{"text":"Central nervous system toxins","correct":false,"visible":false}]},{"id":3951,"text":"Hyperkalemia causes which change in an electrocardiogram?","explanation":null,"reference":null,"responses":[{"text":"Narrow QRS complex","correct":false,"visible":false},{"text":"U waves","correct":false,"visible":false},{"text":"Widened QRS complex","correct":true,"visible":false},{"text":"Small P waves","correct":false,"visible":false},{"text":"Flattened T waves","correct":false,"visible":false}]},{"id":3952,"text":"Which of the following blood vessels return blood from the body to the heart?","explanation":null,"reference":"About the heart and blood vessels - health encyclopedia - university of rochester medical center. Accessed June 19, 2022. https://www.urmc.rochester.edu/encyclopedia/content.aspx?ContentTypeID=90\u0026ContentID=P01761","responses":[{"text":"Aorta and superior vena cava","correct":false,"visible":false},{"text":"Superior vena cava and inferior vena cava","correct":true,"visible":false},{"text":"Pulmonary artery and inferior vena cava","correct":false,"visible":false},{"text":"Left main coronary artery","correct":false,"visible":false},{"text":"Aorta and pulmonary artery","correct":false,"visible":false}]},{"id":3953,"text":"Cannon “a” waves in jugular pulse indicate which of the following?","explanation":null,"reference":"Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 53.","responses":[{"text":"2nd degree heart block","correct":false,"visible":false},{"text":"Tricuspid stenosis","correct":false,"visible":false},{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"Pulmonary stenosis","correct":false,"visible":false},{"text":"Complete heart block","correct":true,"visible":false}]},{"id":3954,"text":"Juxtaglomerular cells are present in which structure of the kidney?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 236.","responses":[{"text":"Collecting duct","correct":false,"visible":false},{"text":"Proximal convoluted tubule","correct":false,"visible":false},{"text":"Collecting tubules","correct":false,"visible":false},{"text":"Glomerulus","correct":false,"visible":false},{"text":"Afferent arteriole","correct":true,"visible":false}]},{"id":3955,"text":"A worker in a calico-printing industry is fired from his job and attempts suicide by ingesting an easily available organic acid at the factory. 30 minutes later, he is found in a state of shock with coffee-ground colored vomitus, severe pain in the throat and abdomen, and twitching of muscles. Which of the following is the most likely organic acid used for attempted suicide?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 485.","responses":[{"text":"Nitric acid","correct":false,"visible":false},{"text":"Acetic acid","correct":false,"visible":false},{"text":"Sulfuric acid","correct":false,"visible":false},{"text":"Hydrochloric acid","correct":false,"visible":false},{"text":"Oxalic acid","correct":true,"visible":false}]},{"id":3956,"text":"Blackening of the stomach, abdominal distension, and chalky white teeth are caused by the ingestion of which of the following mineral acids?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 482-483.","responses":[{"text":"Hydrofluoric acid","correct":false,"visible":false},{"text":"Nitric acid","correct":false,"visible":false},{"text":"Oxalic acid","correct":false,"visible":false},{"text":"Hydrochloric acid","correct":false,"visible":false},{"text":"Sulfuric acid","correct":true,"visible":false}]},{"id":3957,"text":"What is the action of digitalis?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 242, 256.","responses":[{"text":"Increased contraction of ventricles","correct":false,"visible":false},{"text":"Decreased automaticity of atria","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Increased refractory period of AV node","correct":true,"visible":false},{"text":"Decreased excitation of atria","correct":false,"visible":false}]},{"id":3958,"text":"Digitalis is used in atrial fibrillation due to which reason?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 242, 256.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Muscarinic activity","correct":false,"visible":false},{"text":"AV nodal delay","correct":true,"visible":false},{"text":"Cholinergic activity","correct":false,"visible":false},{"text":"Increased cardiac output","correct":false,"visible":false}]},{"id":3984,"text":"For variant (Prinzmetal angina), which of the following drug would be most appropriate for long-term therapy aimed at reducing the incidence or severity of coronary vasospasm?","explanation":null,"reference":"1) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 263.\r\n\r\n2) Rodriguez Ziccardi M, Hatcher JD. Prinzmetal angina. In: StatPearls. StatPearls Publishing; 2022. Accessed June 22, 2022. http://www.ncbi.nlm.nih.gov/books/NBK430776/","responses":[{"text":"Statins","correct":false,"visible":false},{"text":"Diltiazem","correct":true,"visible":false},{"text":"Nitroglycerin","correct":false,"visible":false},{"text":"Propranolol","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false}]},{"id":3989,"text":"A young male drug abuser with a history of hepatitis (HBV), presents with hypertension, abdominal pain, melena, muscle aches, and skin nodules. The laboratory test confirms HbsAg and pANCA positivity. Which one of the following describes the histopathologic appearance of the vasculitis in this case?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 509.","responses":[{"text":"Granulomatous inflammation with presence of giant cells","correct":false,"visible":false},{"text":"Cystic medial degeneration","correct":false,"visible":false},{"text":"Segmental transmural necrotizing inflammation","correct":true,"visible":false},{"text":"Necrotizing and granulomatous inflammation","correct":false,"visible":false},{"text":"Transmural fibrous thickening","correct":false,"visible":false}]},{"id":3990,"text":"Which of the following is a selective beta-1 agonist drug?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 83.","responses":[{"text":"Amrinone","correct":false,"visible":false},{"text":"Digoxin","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Digitoxin","correct":false,"visible":false},{"text":"Dobutamine","correct":true,"visible":false}]},{"id":3998,"text":"Oligemic lung fields on X-ray chest are seen in which of the following conditions?","explanation":"**Tetralogy of Fallot** is a congenital heart defect characterized by four anatomical abnormalities, including ventricular septal defect, pulmonary stenosis, right ventricular hypertrophy, and an overriding aorta. Due to these abnormalities,, there is a decrease in the blood flow to the lungs, leading to **decreased vascularity** or **\"oligemic\"** lung fields on a chest X-ray.\r\n\r\nTricuspid regurgitation primarily affects the right atrium and right ventricle and does not typically cause oligemic lung fields on chest X-ray.\r\n\r\nAtrial septal defect results in a left-to-right shunt and would not be expected to produce oligemic lung fields.\r\n\r\nMitral stenosis mainly affects the left atrium and left ventricle and tends to cause pulmonary congestion, not oligemia.\r\n\r\nVentricular septal defect generally causes increased blood flow to the lungs due to a left-to-right shunt, which would not produce oligemic lung fields.","reference":"Weerakkody Y. Tetralogy of fallot | radiology reference article | radiopaedia. Org. Radiopaedia. doi:10.53347/rID-7356","responses":[{"text":"Tetralogy of Fallot","correct":true,"visible":false},{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Tricuspid regurgitation","correct":false,"visible":false},{"text":"Ventricular septal defect","correct":false,"visible":false}]},{"id":3999,"text":"Which of the following is the mechanism of action of statins?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 290.","responses":[{"text":"Inhibiting conversion of HMG CoA to cholesterol","correct":true,"visible":false},{"text":"Inhibit the metabolism of acetyl CoA","correct":false,"visible":false},{"text":"Binds with bile acids","correct":false,"visible":false},{"text":"Increase the metabolism of cholesterol","correct":false,"visible":false},{"text":"Inhibit the conversion of cholesterol in VLDL","correct":false,"visible":false}]},{"id":4002,"text":"Anticoagulants are given after which of the following mitral valve surgeries?","explanation":"**Anticoagulants** are usually required after **mechanical valve replacement** to prevent thromboembolic complications. Mechanical valves have a higher propensity for clot formation due to their synthetic material, so **lifelong anticoagulation therapy** is often recommended to minimize this risk.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 524.","responses":[{"text":"Transcatheter Aortic Valve Replacement (TAVR)","correct":false,"visible":false},{"text":"Bioprosthetic valve replacement","correct":false,"visible":false},{"text":"Balloon valvuloplasty","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Mechanical valve replacement","correct":true,"visible":false}]},{"id":4029,"text":"What amount of charcoal is required as an antidote?","explanation":"**Activated charcoal** is used in the management of poisoning, typically within one hour of the ingestion of a toxic substance. It works by binding to the toxin in the gastrointestinal tract, thus reducing its absorption into the systemic circulation. In adults, the general dose of activated charcoal is **60-100 gm**.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 475.","responses":[{"text":"60-100 gm","correct":true,"visible":false},{"text":"2-4 gm","correct":false,"visible":false},{"text":"5-10 gm","correct":false,"visible":false},{"text":"15-30 gm","correct":false,"visible":false},{"text":"100-200 gm","correct":false,"visible":false}]},{"id":4038,"text":"In which type of poisoning is stomach wash not contraindicated?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 486-487.","responses":[{"text":"Hydrochloric acid","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Carbolic acid","correct":true,"visible":false},{"text":"Carboxylic acid","correct":false,"visible":false},{"text":"Sulfuric acid","correct":false,"visible":false}]},{"id":4040,"text":"In which kind of poisoning is a bone sample obtained?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 113.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Corrosive","correct":false,"visible":false},{"text":"Heavy metals","correct":true,"visible":false},{"text":"Diarrhea","correct":false,"visible":false},{"text":"Organic acid","correct":false,"visible":false}]},{"id":4043,"text":"In a private clinic in Lahore, a cholera epidemic has broken out. The doctor will call which of the following?","explanation":null,"reference":"Ilyas M. Public Health and Community Medicine. 8th ed. TIME Publisher; 2016:118.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Health authorities","correct":true,"visible":false},{"text":"Area magistrate","correct":false,"visible":false},{"text":"The police","correct":false,"visible":false},{"text":"Hospital incharge","correct":false,"visible":false}]},{"id":4101,"text":"Which of the following drugs has to be taken by a patient for a lifetime after mechanical replacement surgery of the mitral valve?","explanation":null,"reference":"Jang I, Choo S, Kim K. Warfarin therapy after mechanical valve replacement: a tool for predicting bleeding events. The Journal of Heart Valve Disease. Published March 2017. https://pubmed.ncbi.nlm.nih.gov/28820554/","responses":[{"text":"Vitamin K1","correct":false,"visible":false},{"text":"Coumarin","correct":true,"visible":false},{"text":"Streptokinase","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false}]},{"id":4109,"text":"Which of the following can be used for the diagnosis of rheumatic fever?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 559.","responses":[{"text":"Arthralgia with fever and raised ESR","correct":false,"visible":false},{"text":"Arthralgia with prolonged PR fever","correct":false,"visible":false},{"text":"Carditis with arthralgia and fever","correct":true,"visible":false},{"text":"Arthralgia only","correct":false,"visible":false},{"text":"Arthralgia with fever","correct":false,"visible":false}]},{"id":4110,"text":"Which of the following is the gold standard for the diagnosis of constrictive pericarditis?","explanation":"The gold standard for the diagnosis of constrictive pericarditis is **cardiac catheterization**. This invasive procedure allows for the measurement of intracardiac pressures and the assessment of the hemodynamics, which are critical for distinguishing constrictive pericarditis from other conditions such as restrictive cardiomyopathy. Cardiac catheterization can provide definitive evidence of the thickened pericardium and the characteristic dip-and-plateau or \"square root sign\" in ventricular pressure tracings indicative of constrictive pericarditis.\r\n\r\nEchocardiography is a useful non-invasive tool recommended for initial evaluation that provides important clues for the diagnosis of constrictive pericarditis, including abnormal septal motion and pericardial thickening, but it may not always be definitive.","reference":"(1) Diaz-Arocutipa C, Chumbiauca M, Medina HM, Hernandez AV, Vicent L. Echocardiographic criteria to differentiate constrictive pericarditis from restrictive cardiomyopathy: a meta-analysis. CJC Open. Published September 1, 2023. Accessed February 2, 2024. https://www.sciencedirect.com/science/article/pii/S2589790X23001282\r\n\r\n(2) Miranda WR, Oh JK. Constrictive pericarditis: a practical clinical approach. Progress in Cardiovascular Diseases. Published February 2017. https://pubmed.ncbi.nlm.nih.gov/28062267/","responses":[{"text":"Chest X-ray","correct":false,"visible":false},{"text":"Echocardiography","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"CT scanning","correct":false,"visible":false},{"text":"Cardiac catheterization","correct":true,"visible":false}]},{"id":4165,"text":"Which of the following is one of the principal components of an atherosclerotic plaque?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 498.","responses":[{"text":"Predominantly eosinophils","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false},{"text":"Amyloid","correct":false,"visible":false},{"text":"Fibrinous material","correct":false,"visible":false},{"text":"Epithelioid cells","correct":false,"visible":false}]},{"id":4324,"text":"What is the percentage of coronary artery stenosis in typical angina?","explanation":null,"reference":"Shahjehan RD, Bhutta BS. Coronary artery disease. In: StatPearls. StatPearls Publishing; 2022. Accessed June 24, 2022. http://www.ncbi.nlm.nih.gov/books/NBK564304/","responses":[{"text":"50%","correct":false,"visible":false},{"text":"10%","correct":false,"visible":false},{"text":"20%","correct":false,"visible":false},{"text":"90%","correct":true,"visible":false},{"text":"40%","correct":false,"visible":false}]},{"id":10809,"text":"A 60-year-old man comes to the clinic with complaints of breathlessness and chest pain on exertion for 1 year. On examination, the blood pressure is 110/90 mm Hg. A crescendo-decrescendo murmur is heard over the right upper sternal border during systole. What is the likely diagnosis?","explanation":null,"reference":"Feather A, Randall D, Randall D, Waterhouse M, Waterhouse M. Kumar \u0026 Clark’s Clinical Medicine. 10th ed. Elsevier; 2021: 1097-1099.","responses":[{"text":"Mitral stenosis","correct":false,"visible":false},{"text":"Aortic stenosis","correct":true,"visible":false},{"text":"Aortic regurgitation","correct":false,"visible":false},{"text":"Pulmonary regurgitation","correct":false,"visible":false},{"text":"Tricuspid regurgitation","correct":false,"visible":false}]},{"id":10810,"text":"A 30-year-old female presents to the clinic for routine examination. Chest auscultation reveals an ejection systolic murmur that radiates to the left sternal border and a soft P2 sound. What is the most likely diagnosis?","explanation":null,"reference":"Feather A, Randall D, Randall D, Waterhouse M, Waterhouse M. Kumar \u0026 Clark’s Clinical Medicine. 10th ed. Elsevier; 2021: 1101-1102.","responses":[{"text":"Atrial septal defect","correct":false,"visible":false},{"text":"Tricuspid regurgitation","correct":false,"visible":false},{"text":"Aortic stenosis","correct":false,"visible":false},{"text":"Pulmonary stenosis","correct":true,"visible":false},{"text":"Mitral regurgitation","correct":false,"visible":false}]},{"id":14240,"text":"A 55-year-old woman presents to the emergency department with sudden onset of chest pain. An ECG shows ST-segment elevations in leads II, III, avF, V4, V5, and V6. What is the most likely diagnosis?","explanation":"The most likely diagnosis for this patient is **inferolateral myocardial infarction (MI)**. ST-segment elevations in leads **II, III, avF** (which represent the inferior wall of the heart), along with elevations in **V4, V5, and V6** (lateral wall), point to an infarction affecting both the inferior and lateral regions of the heart.\r\n\r\nAnterolateral MI would typically involve leads V1-V6, I, aVL, but not II, III, avF. Posterior wall MI often presents with ST-segment depression in the anterior leads (V1-V3) rather than elevation. Anteroseptal MI would primarily involve leads V1-V4, and an inferior wall MI would generally show changes in leads II, III, and avF but not the lateral leads.","reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 436.","responses":[{"text":"Anterolateral MI","correct":false,"visible":false},{"text":"Inferolateral MI","correct":true,"visible":false},{"text":"Inferior wall MI","correct":false,"visible":false},{"text":"Posterior wall MI","correct":false,"visible":false},{"text":"Anteroseptal MI","correct":false,"visible":false}]},{"id":14981,"text":"A 64-year-old male with hypertrophic obstructive cardiomyopathy and a previous history of MI presents to the clinic with a complaint of recurrent syncope. Echocardiogram shows an increase in left ventricular wall thickness from last year. \r\nWhich of the following is the most suitable option to prevent sudden cardiac death in this patient?","explanation":null,"reference":"Davidsons Principles and Practice of Medicine, 24th edition, page 475\r\nJameson JL, Fauci AS, Kasper DL, Hauser SL, Longo DL, Loscalzo J, eds. Harrison’s Principles of Internal Medicine. 20th ed. McGraw-Hill Education; 2018: 1795-1796.","responses":[{"text":"β-blockers","correct":false,"visible":false},{"text":"Septal ablation","correct":false,"visible":false},{"text":"Diltiazem","correct":false,"visible":false},{"text":"Implantable cardioverter-defibrillator (ICD)","correct":true,"visible":false},{"text":"Digoxin","correct":false,"visible":false}]},{"id":15256,"text":"Which of the following types of shock is characterized by warm peripheries?","explanation":null,"reference":"(1) Kumar and Clark's Clinical Medicine, 10th edition, page no. 218 (Box 10.9)\r\n\r\n(2) Standl T, Annecke T, Cascorbi I, R. Heller A, Sabashnikov A, Teske W. The nomenclature, definition and distinction of types of shock. Deutsches Ärzteblatt International. Published November 2018. Accessed February 4, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6323133/","responses":[{"text":"Cardiogenic shock","correct":false,"visible":false},{"text":"Obstructive shock","correct":false,"visible":false},{"text":"Septic shock","correct":false,"visible":false},{"text":"Distributive shock","correct":true,"visible":false},{"text":"Hypovolemic shock","correct":false,"visible":false}]},{"id":17857,"text":"A 51-year-old patient presents to the emergency department with chest pain. An ECG shows ST-segment elevation. On examination, there is sinus bradycardia. How can heart rate be increased?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 469.","responses":[{"text":"Verapamil","correct":false,"visible":false},{"text":"Atropine","correct":true,"visible":false},{"text":"Clonidine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false}]},{"id":17858,"text":"What would be the preferred initial management for a condition with an ECG showing paroxysmal bouts of normal but irregular QRS complexes with no P waves?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 471.","responses":[{"text":"Defibrillation","correct":false,"visible":false},{"text":"Amiodarone","correct":false,"visible":false},{"text":"Calcium channel blockers","correct":false,"visible":false},{"text":"Digoxin","correct":false,"visible":false},{"text":"Beta-blockers","correct":true,"visible":false}]},{"id":17860,"text":"An electrocardiogram of a patient shows tachycardia and broad, abnormal QRS complexes with a rate of more than 120 beats/min, with a blood pressure of 90/60 mmHg. What is the most appropriate treatment?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 475.","responses":[{"text":"Beta-blockers","correct":false,"visible":false},{"text":"Amiodarone","correct":false,"visible":false},{"text":"Quinidine","correct":false,"visible":false},{"text":"Synchronised DC cardioversion","correct":true,"visible":false},{"text":"Digoxin","correct":false,"visible":false}]},{"id":17862,"text":"A patient presents to the emergency with typical chest pain of 3 hours duration. Electrocardiogram shows an ST-segment elevation What will be the most appropriate treatment?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 499.","responses":[{"text":"Fondaparinux","correct":false,"visible":false},{"text":"Percutaneous coronary intervention","correct":true,"visible":false},{"text":"Coronary artery bypass graft","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false},{"text":"Thrombolysis","correct":false,"visible":false}]},{"id":17863,"text":"A 41-year-old patient visits the clinic. He has a history of diabetes for the last 8 years. He has a persistently elevated blood pressure of 160/100 mmHg. What is the most appropriate antihypertensive?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 758.","responses":[{"text":"Thiazide diuretics","correct":false,"visible":false},{"text":"Nitroprusside","correct":false,"visible":false},{"text":"Calcium channel blockers","correct":false,"visible":false},{"text":"Angiotensin converting enzyme inhibitors or angiotensin receptor blockers","correct":true,"visible":false},{"text":"Beta-blockers","correct":false,"visible":false}]},{"id":17927,"text":"A young man presents to the hospital with a history of hypertrophic obstructive cardiomyopathy. What will be the best initial management for him?","explanation":null,"reference":"Davidson's Principles and Practice of Medicine, 24th edition, page 540.","responses":[{"text":"Reassurance","correct":false,"visible":false},{"text":"Alcohol (non surgical) ablation of the septum","correct":false,"visible":false},{"text":"Dual chamber pacing","correct":false,"visible":false},{"text":"Implantable cardioverter defibrillator (ICD)","correct":false,"visible":false},{"text":"Beta blockers","correct":true,"visible":false}]},{"id":17929,"text":"What would be the treatment of New York Heart Association classification class III heart failure?","explanation":null,"reference":"Davidson's Principles and Practice of Medicine, 24th edition, pages 465-467.","responses":[{"text":"Diuretics, angiotensin converting enzyme inhibitors and beta blockers","correct":true,"visible":false},{"text":"Ivabradine only","correct":false,"visible":false},{"text":"Spironolactone and diuretics","correct":false,"visible":false},{"text":"Diuretics and angiotensin receptor blockers","correct":false,"visible":false},{"text":"Digoxin","correct":false,"visible":false}]},{"id":19872,"text":"Which of the following drugs should be used for rate control in atrial fibrillation?","explanation":null,"reference":"(1) Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 414.\r\n\r\n\r\n(2) Nesheiwat Z, Goyal A, Jagtap M. Atrial fibrillation. StatPearls. Published 2023. Accessed September 26, 2023. http://www.ncbi.nlm.nih.gov/books/NBK526072/","responses":[{"text":"Digoxin","correct":false,"visible":false},{"text":"Amiodrone","correct":false,"visible":false},{"text":"Beta blockers","correct":true,"visible":false},{"text":"Lisinopril","correct":false,"visible":false},{"text":"Hydrochlorothiazide","correct":false,"visible":false}]}
]

export default a